files.frontend/.env.local:
{%- if cookiecutter.generate_env -%}
# {{ cookiecutter.project_name }} Frontend Environment Variables
# Generated automatically - ready for local development

# Backend API URL (server-side only - not exposed to browser)
BACKEND_URL=http://localhost:{{ cookiecutter.backend_port }}

# WebSocket URL for real-time features (server-side)
BACKEND_WS_URL=ws://localhost:{{ cookiecutter.backend_port }}

# WebSocket URL exposed to browser (NEXT_PUBLIC_ prefix required for client-side access)
NEXT_PUBLIC_WS_URL=ws://localhost:{{ cookiecutter.backend_port }}
{%- if cookiecutter.enable_oauth %}

# Public API URL for OAuth redirects (exposed to browser)
NEXT_PUBLIC_API_URL=http://localhost:{{ cookiecutter.backend_port }}
{%- endif %}

# Max file upload size in MB (must match backend MAX_UPLOAD_SIZE_MB)
NEXT_PUBLIC_MAX_UPLOAD_SIZE_MB=50
{%- if cookiecutter.enable_logfire %}

# Logfire/OpenTelemetry (server-side instrumentation)
# Get your write token from: https://logfire.pydantic.dev
# OTEL_EXPORTER_OTLP_ENDPOINT=https://logfire-api.pydantic.dev
# OTEL_EXPORTER_OTLP_HEADERS=Authorization=your-logfire-write-token
{%- endif %}
{% else -%}
# .env.local file not generated - copy from .env.example
# cp .env.example .env.local
{%- endif %}

